SELECT id, gateway_id, api_key, rate_limit, expire_time, status, create_time, update_time
FROM mcp_gateway_auth
WHERE id = #{id}

SELECT id, gateway_id, api_key, rate_limit, expire_time, status, create_time, update_time
FROM mcp_gateway_auth
WHERE gateway_id = #{gatewayId}

SELECT id, gateway_id, api_key, rate_limit, expire_time, status, create_time, update_time
FROM mcp_gateway_auth
WHERE api_key = #{apiKey}
